import subprocess

def get_file_type(file_path):
    try:
        result = subprocess.run(
            ['file', file_path],
            capture_output=True,
            text=True,
            check=True
        )
        return result.stdout.strip()
    except subprocess.CalledProcessError as e:
        return f"Error: {e.stderr.strip()}"

# Example usage
print(get_file_type('/path/to/file.txt'))

This script runs the `file` command on the specified file and returns its output as a string.
